    class SmartAuthClient:
        """Fetches and caches a SMART on FHIR Bearer token.

        auth_type values:
        - "jwt_assertion": SMART Backend Services with RSA/EC private key (RFC 7523)
        - "client_secret": OAuth2 client credentials with symmetric secret
        - "none": No authentication (open servers, dev/test only)
        """

        def __init__(self, token_url: str, client_id: str, auth_type: str,
                     private_key_pem: str = "", client_secret: str = "", scope: str = "",
                     kid: str = "", private_key_algorithm: str = "RS384") -> None:
            self._token_url = token_url
            self._client_id = client_id
            self._auth_type = auth_type
            self._private_key_pem = private_key_pem
            self._client_secret = client_secret
            self._scope = scope
            self._kid = kid
            self._private_key_algorithm = private_key_algorithm
            self._access_token: Optional[str] = None
            self._expires_at: Optional[datetime] = None

            if auth_type == "jwt_assertion":
                _SUPPORTED_ALGORITHMS = {"RS384", "ES384"}
                if private_key_algorithm not in _SUPPORTED_ALGORITHMS:
                    raise ValueError(
                        f"private_key_algorithm {private_key_algorithm!r} is not supported. "
                        f"Use one of: {sorted(_SUPPORTED_ALGORITHMS)}. "
                        f"Per the SMART on FHIR Backend Services spec, clients SHALL support RS384 and ES384."
                    )

        def get_token(self) -> str:
            if self._auth_type == "none":
                return ""
            if self._access_token and self._expires_at:
                if datetime.now(timezone.utc) < self._expires_at:
                    return self._access_token
            self._refresh_token()
            return self._access_token

        def _refresh_token(self) -> None:
            if self._auth_type == "jwt_assertion":
                data = self._jwt_assertion_data()
                post_kwargs: dict = {}
            elif self._auth_type == "client_secret":
                data = self._client_secret_data()
                post_kwargs = {"auth": (self._client_id, self._client_secret)}
            else:
                raise ValueError(f"Unsupported auth_type: {self._auth_type!r}. "
                                 f"Use 'jwt_assertion', 'client_secret', or 'none'.")
            resp = requests.post(
                self._token_url, data=data,
                headers={"Content-Type": "application/x-www-form-urlencoded"},
                timeout=TOKEN_TIMEOUT,
                **post_kwargs,
            )
            if resp.status_code != 200:
                raise RuntimeError(f"SMART token request failed (HTTP {resp.status_code}): {resp.text}")
            body = resp.json()
            self._access_token = body["access_token"]
            expires_in = int(body.get("expires_in", 300))
            self._expires_at = datetime.now(timezone.utc) + timedelta(seconds=expires_in - 30)

        def _jwt_assertion_data(self) -> dict:
            now = datetime.now(timezone.utc)
            payload = {
                "iss": self._client_id, "sub": self._client_id, "aud": self._token_url,
                "jti": str(uuid.uuid4()), "iat": now, "exp": now + timedelta(minutes=5),
            }
            if not self._kid:
                raise ValueError(
                    "kid is required for jwt_assertion auth. "
                    "Provide the key ID (kid) that identifies the private key "
                    "registered with the FHIR server's JWK Set."
                )
            jwt_headers = {"kid": self._kid, "typ": "JWT"}
            assertion = jwt.encode(payload, self._private_key_pem, algorithm=self._private_key_algorithm, headers=jwt_headers)
            data = {
                "grant_type": "client_credentials",
                "client_assertion_type": "urn:ietf:params:oauth:client-assertion-type:jwt-bearer",
                "client_assertion": assertion,
            }
            if self._scope:
                data["scope"] = self._scope
            return data

        def _client_secret_data(self) -> dict:
            # client_id and client_secret are NOT included in the POST body.
            # Per SMART client-confidential-symmetric spec, they are passed via
            # HTTP Basic auth (Authorization: Basic B64(client_id:client_secret)).
            data = {"grant_type": "client_credentials"}
            if self._scope:
                data["scope"] = self._scope
            return data


    def discover_token_url(base_url: str) -> str:
        """Fetch the OAuth2 token endpoint from the FHIR server's SMART configuration.

        Per SMART on FHIR Backend Services spec, servers publish their OAuth endpoints at:
        {base_url}/.well-known/smart-configuration

        Returns the token_endpoint URL.
        Raises RuntimeError if discovery fails or token_endpoint is absent.
        """
        discovery_url = base_url.rstrip("/") + "/.well-known/smart-configuration"
        resp = requests.get(
            discovery_url,
            headers={"Accept": "application/json"},
            timeout=TOKEN_TIMEOUT,
        )
        if resp.status_code != 200:
            raise RuntimeError(
                f"SMART configuration discovery failed (HTTP {resp.status_code}) at {discovery_url}: "
                f"{resp.text}"
            )
        config = resp.json()
        token_endpoint = config.get("token_endpoint")
        if not token_endpoint:
            raise RuntimeError(
                f"SMART configuration at {discovery_url} does not contain 'token_endpoint'. "
                f"Keys present: {list(config.keys())}"
            )
        return token_endpoint


    class FhirHttpClient:
        """HTTP client for FHIR R4 REST API with auth injection and retry logic.

        Retries on 429/500/503 with exponential backoff. Honors Retry-After on 429.
        All requests have timeout=60 to prevent hangs.
        """

        def __init__(self, base_url: str, auth_client: SmartAuthClient) -> None:
            self._base_url = base_url.rstrip("/") + "/"
            self._auth_client = auth_client
            self._session = requests.Session()

        def _headers(self) -> dict:
            token = self._auth_client.get_token()
            h = {"Accept": "application/fhir+json"}
            if token:
                h["Authorization"] = f"Bearer {token}"
            return h

        def get(self, resource_type: str, params: Optional[dict] = None) -> requests.Response:
            url = urljoin(self._base_url, resource_type)
            return self.get_url(url, params=params)

        def get_url(self, url: str, params: Optional[dict] = None) -> requests.Response:
            backoff = INITIAL_BACKOFF
            for attempt in range(MAX_RETRIES):
                resp = self._session.get(url, params=params, headers=self._headers(), timeout=HTTP_TIMEOUT)
                if resp.status_code not in RETRIABLE_STATUS_CODES:
                    return resp
                if attempt < MAX_RETRIES - 1:
                    retry_after = resp.headers.get("Retry-After")
                    if retry_after:
                        try:
                            sleep_seconds = float(retry_after)
                        except ValueError:
                            sleep_seconds = backoff  # Retry-After is an HTTP-date; fall back to backoff
                    else:
                        sleep_seconds = backoff
                    time.sleep(sleep_seconds)
                    backoff *= 2
            return resp


    def _next_link(bundle: dict) -> Optional[str]:
        for link in bundle.get("link", []):
            if link.get("relation") == "next":
                return link.get("url")
        return None


    def iter_bundle_pages(
        client: FhirHttpClient,
        resource_type: str,
        params: Optional[dict] = None,
        max_records: Optional[int] = None,
        page_delay: float = PAGE_DELAY,
    ) -> Iterator[dict]:
        """Yield FHIR resources from a paginated search, following Bundle next links."""
        count = 0
        resp = client.get(resource_type, params=params)
        if resp.status_code != 200:
            raise RuntimeError(
                f"FHIR search failed for {resource_type} (HTTP {resp.status_code}): {resp.text}"
            )

        while True:
            bundle = resp.json()
            if bundle.get("resourceType") != "Bundle":
                raise RuntimeError(
                    f"Expected Bundle for {resource_type}, got: {bundle.get('resourceType')}"
                )
            for entry in bundle.get("entry", []):
                resource = entry.get("resource")
                if resource:
                    yield resource
                    count += 1
                    if max_records is not None and count >= max_records:
                        return

            next_url = _next_link(bundle)
            if not next_url:
                return

            if page_delay > 0:
                time.sleep(page_delay)
            resp = client.get_url(next_url)
            if resp.status_code != 200:
                raise RuntimeError(
                    f"FHIR pagination failed for {resource_type} (HTTP {resp.status_code}): {resp.text}"
                )


    def _safe(d, *keys, default=None):
        """Safely navigate nested dicts. Returns default if any key is missing."""
        for k in keys:
            if not isinstance(d, dict):
                return default
            d = d.get(k)
            if d is None:
                return default
        return d


    def extract_record(resource: dict, resource_type: str) -> dict:
        """Map a raw FHIR resource to hybrid schema format (typed fields + raw_json).

        Returns raw field values -- do NOT pre-convert types; the framework handles coercion.
        Absent struct fields return None, not {}.
        """
        meta = resource.get("meta") or {}
        record = {
            "id": resource.get("id"),
            "resourceType": resource.get("resourceType", resource_type),
            "lastUpdated": meta.get("lastUpdated"),
            "raw_json": json.dumps(resource),
        }
        extractor = _EXTRACTORS.get(resource_type)
        if extractor:
            record.update(extractor(resource))
        return record


    # ---------------------------------------------------------------------------
    # Resource-specific field extractors
    # ---------------------------------------------------------------------------

    def _patient(r):
        name = ((r.get("name") or [{}])[0]) or {}
        return {
            "gender": r.get("gender"),
            "birthDate": r.get("birthDate"),
            "active": r.get("active"),
            "name_text": name.get("text"),
            "name_family": name.get("family"),
        }


    def _observation(r):
        code = r.get("code") or {}
        codings = code.get("coding") or [{}]
        coding = (codings[0] if codings else None) or {}
        vq = r.get("valueQuantity") or {}
        return {
            "status": r.get("status"),
            "code_text": code.get("text"),
            "code_system": coding.get("system"),
            "code_code": coding.get("code"),
            "subject_reference": _safe(r, "subject", "reference"),
            "effective_datetime": r.get("effectiveDateTime"),
            "value_quantity_value": vq.get("value"),
            "value_quantity_unit": vq.get("unit"),
            "value_string": r.get("valueString"),
            "issued": r.get("issued"),
        }


    def _condition(r):
        cs = _safe(r, "clinicalStatus", "coding") or [{}]
        vs = _safe(r, "verificationStatus", "coding") or [{}]
        return {
            "clinical_status": (cs[0] or {}).get("code"),
            "verification_status": (vs[0] or {}).get("code"),
            "code_text": _safe(r, "code", "text"),
            "subject_reference": _safe(r, "subject", "reference"),
            "onset_datetime": r.get("onsetDateTime"),
            "recorded_date": r.get("recordedDate"),
        }


    def _encounter(r):
        class_ = r.get("class") or {}
        period = r.get("period") or {}
        return {
            "status": r.get("status"),
            "class_code": class_.get("code"),
            "subject_reference": _safe(r, "subject", "reference"),
            "period_start": period.get("start"),
            "period_end": period.get("end"),
        }


    def _procedure(r):
        return {
            "status": r.get("status"),
            "code_text": _safe(r, "code", "text"),
            "subject_reference": _safe(r, "subject", "reference"),
            "performed_datetime": r.get("performedDateTime"),
        }


    def _medication_request(r):
        return {
            "status": r.get("status"),
            "intent": r.get("intent"),
            "medication_text": _safe(r, "medicationCodeableConcept", "text"),
            "subject_reference": _safe(r, "subject", "reference"),
            "authored_on": r.get("authoredOn"),
        }


    def _diagnostic_report(r):
        return {
            "status": r.get("status"),
            "code_text": _safe(r, "code", "text"),
            "subject_reference": _safe(r, "subject", "reference"),
            "effective_datetime": r.get("effectiveDateTime"),
            "issued": r.get("issued"),
        }


    def _allergy(r):
        cs = _safe(r, "clinicalStatus", "coding") or [{}]
        vs = _safe(r, "verificationStatus", "coding") or [{}]
        return {
            "clinical_status": (cs[0] or {}).get("code"),
            "verification_status": (vs[0] or {}).get("code"),
            "code_text": _safe(r, "code", "text"),
            "patient_reference": _safe(r, "patient", "reference"),
            "recorded_date": r.get("recordedDate"),
        }


    def _immunization(r):
        return {
            "status": r.get("status"),
            "vaccine_code_text": _safe(r, "vaccineCode", "text"),
            "patient_reference": _safe(r, "patient", "reference"),
            "occurrence_datetime": r.get("occurrenceDateTime"),
        }


    def _coverage(r):
        payors = r.get("payor") or [None]
        period = r.get("period") or {}
        return {
            "status": r.get("status"),
            "beneficiary_reference": _safe(r, "beneficiary", "reference"),
            "payor_reference": _safe(payors[0] or {}, "reference"),
            "period_start": period.get("start"),
            "period_end": period.get("end"),
        }


    def _care_plan(r):
        period = r.get("period") or {}
        return {
            "status": r.get("status"),
            "intent": r.get("intent"),
            "subject_reference": _safe(r, "subject", "reference"),
            "period_start": period.get("start"),
            "period_end": period.get("end"),
        }


    def _goal(r):
        return {
            "lifecycle_status": r.get("lifecycleStatus"),
            "description_text": _safe(r, "description", "text"),
            "subject_reference": _safe(r, "subject", "reference"),
            "start_date": r.get("startDate"),
        }


    def _device(r):
        names = r.get("deviceName") or [{}]
        return {
            "status": r.get("status"),
            "device_name": (names[0] or {}).get("name"),
            "type_text": _safe(r, "type", "text"),
            "patient_reference": _safe(r, "patient", "reference"),
        }


    def _document_reference(r):
        return {
            "status": r.get("status"),
            "type_text": _safe(r, "type", "text"),
            "subject_reference": _safe(r, "subject", "reference"),
            "date": r.get("date"),
        }


    _EXTRACTORS = {
        "Patient": _patient,
        "Observation": _observation,
        "Condition": _condition,
        "Encounter": _encounter,
        "Procedure": _procedure,
        "MedicationRequest": _medication_request,
        "DiagnosticReport": _diagnostic_report,
        "AllergyIntolerance": _allergy,
        "Immunization": _immunization,
        "Coverage": _coverage,
        "CarePlan": _care_plan,
        "Goal": _goal,
        "Device": _device,
        "DocumentReference": _document_reference,
    }


    ########################################################
    # src/databricks/labs/community_connector/sources/fhir/validate_auth.py
    ########################################################

    def validate(config: dict) -> None:
        auth_type = config.get("auth_type", "none")
        base_url = config.get("base_url", "").rstrip("/")

        if not base_url:
            _fail("'base_url' is required in config.")

        print(f"  base_url   : {base_url}")
        print(f"  auth_type  : {auth_type}")

        # Step 1: Resolve token URL (or skip for none)
        token_url = config.get("token_url", "").strip()
        if auth_type != "none" and not token_url:
            print("\n[1/3] Discovering token endpoint via .well-known/smart-configuration ...")
            try:
                token_url = discover_token_url(base_url)
                print(f"  token_url  : {token_url}  (auto-discovered)")
            except RuntimeError as exc:
                _fail(f"Token endpoint discovery failed:\n  {exc}")
        elif token_url:
            print(f"  token_url  : {token_url}")

        # Step 2: Obtain an access token
        if auth_type != "none":
            print(f"\n[2/3] Requesting access token ({auth_type}) ...")
            auth_client = SmartAuthClient(
                token_url=token_url,
                client_id=config.get("client_id", ""),
                auth_type=auth_type,
                private_key_pem=config.get("private_key_pem", ""),
                client_secret=config.get("client_secret", ""),
                scope=config.get("scope", ""),
                kid=config.get("kid", ""),
                private_key_algorithm=config.get("private_key_algorithm", "RS384"),
            )
            try:
                token = auth_client.get_token()
            except (RuntimeError, ValueError) as exc:
                _fail(f"Token request failed:\n  {exc}")
            print(f"  access token obtained  ({len(token)} chars)")
        else:
            print("\n[2/3] auth_type=none — skipping token request.")
            auth_client = SmartAuthClient(
                token_url="", client_id="", auth_type="none",
            )

        # Step 3: Hit the FHIR server metadata endpoint to confirm connectivity
        print("\n[3/3] Confirming FHIR server connectivity (GET /metadata) ...")
        client = FhirHttpClient(base_url=base_url, auth_client=auth_client)
        resp = client.get("metadata")
        if resp.status_code != 200:
            _fail(
                f"GET {base_url}/metadata returned HTTP {resp.status_code}.\n"
                f"  Response: {resp.text[:300]}"
            )
        body = resp.json()
        fhir_version = body.get("fhirVersion", "unknown")
        software = body.get("software", {}).get("name", "unknown")
        print(f"  FHIR version : {fhir_version}")
        print(f"  Server       : {software}")

        print("\n✓ Credentials validated successfully. The connector can reach the FHIR server.\n")


    def _fail(message: str) -> None:
        print(f"\n✗ Validation failed: {message}\n", file=sys.stderr)
        sys.exit(1)


    def main() -> None:
        parser = argparse.ArgumentParser(
            description="Validate FHIR connector credentials against a real FHIR server."
        )
        parser.add_argument(
            "--config", required=True,
            help="Path to dev_config.json produced by authenticate.py",
        )
        args = parser.parse_args()

        config_path = Path(args.config)
        if not config_path.exists():
            _fail(f"Config file not found: {config_path}")

        with open(config_path) as f:
            config = json.load(f)

        print(f"\nValidating FHIR credentials from: {config_path}\n")
        validate(config)


    if __name__ == "__main__":
        main()


    ########################################################
    # src/databricks/labs/community_connector/sources/fhir/fhir.py
    ########################################################

    class FhirLakeflowConnect(LakeflowConnect):
        """LakeflowConnect implementation for FHIR R4 servers."""

        def __init__(self, options: dict[str, str]) -> None:
            super().__init__(options)

            auth_type = options.get("auth_type", "none")
            token_url = options.get("token_url", "").strip()

            if not token_url and auth_type != "none":
                token_url = discover_token_url(options["base_url"])

            auth_client = SmartAuthClient(
                token_url=token_url,
                client_id=options.get("client_id", ""),
                auth_type=auth_type,
                private_key_pem=options.get("private_key_pem", ""),
                client_secret=options.get("client_secret", ""),
                scope=options.get("scope", ""),
                kid=options.get("kid", ""),
                private_key_algorithm=options.get("private_key_algorithm", "RS384"),
            )
            self._client = FhirHttpClient(base_url=options["base_url"], auth_client=auth_client)

            # Cap cursor at init time -- never chase data written after this trigger started.
            self._init_ts = datetime.now(timezone.utc).isoformat()

            resource_types_opt = options.get("resource_types", "").strip()
            self._resources = (
                [r.strip() for r in resource_types_opt.split(",") if r.strip()]
                if resource_types_opt
                else list(DEFAULT_RESOURCES)
            )

        def list_tables(self) -> list[str]:
            return list(self._resources)

        def get_table_schema(self, table_name: str, table_options: dict[str, str]) -> StructType:
            self._validate_table(table_name)
            return get_schema(table_name)

        def read_table_metadata(self, table_name: str, table_options: dict[str, str]) -> dict:
            self._validate_table(table_name)
            return {
                "primary_keys": ["id"],
                "cursor_field": CURSOR_FIELD,
                "ingestion_type": "cdc",
            }

        def read_table(
            self, table_name: str, start_offset: dict, table_options: dict[str, str]
        ) -> tuple[Iterator[dict], dict]:
            """Fetch FHIR resources with bundle pagination and _lastUpdated incremental sync.

            Uses max_records_per_batch admission control (always required for CDC tables).
            Short-circuits when cursor >= _init_ts to prevent chasing live writes.
            """
            self._validate_table(table_name)

            since = start_offset.get("cursor") if start_offset else None
            if since and since >= self._init_ts:
                return iter([]), start_offset

            page_size = int(table_options.get("page_size", str(DEFAULT_PAGE_SIZE)))
            max_records = int(table_options.get("max_records_per_batch", str(DEFAULT_MAX_RECORDS)))
            page_delay = float(table_options.get("page_delay", str(PAGE_DELAY)))

            params: dict[str, str] = {"_count": str(page_size)}
            if since:
                params["_lastUpdated"] = f"gt{since}"

            records = []
            for resource in iter_bundle_pages(self._client, table_name, params, max_records=max_records, page_delay=page_delay):
                records.append(extract_record(resource, table_name))

            if not records:
                return iter([]), start_offset or {}

            # Detect if server ignored the _lastUpdated filter.
            # Only raise if there are records with a datable lastUpdated AND none of them are
            # newer than since — that combination is evidence the filter was ignored.
            # Records with null lastUpdated are excluded from this check (cardinality 0..1 in spec).
            if since:
                has_datable = [r for r in records if r.get(CURSOR_FIELD)]
                newer = [r for r in has_datable if r[CURSOR_FIELD] > since]
                if has_datable and not newer:
                    raise RuntimeError(
                        f"FHIR server appears to have ignored the '_lastUpdated=gt{since}' filter — "
                        f"all {len(has_datable)} records with a lastUpdated for '{table_name}' have "
                        f"lastUpdated <= '{since}'. "
                        f"This server may not support the _lastUpdated search parameter. "
                        f"See README.md for server requirements."
                    )

            # Advance cursor to max lastUpdated across batch.
            # ISO8601 string comparison is correct for FHIR instants (always timezone-qualified).
            cursors = [r[CURSOR_FIELD] for r in records if r.get(CURSOR_FIELD)]
            if not cursors:
                return iter(records), start_offset or {}

            last_cursor = max(cursors)
            end_offset = {"cursor": last_cursor}

            if start_offset and start_offset == end_offset:
                return iter([]), start_offset

            return iter(records), end_offset

        def _validate_table(self, table_name: str) -> None:
            if table_name not in self._resources:
                raise ValueError(
                    f"Resource type '{table_name}' is not configured. "
                    f"Configured: {self._resources}"
                )


